  capwesome_diff_business_capawesome: '<strong class="text-white">Capawesome:</strong> Solo founder, sustainable business model (also good!)',
  capwesome_diff_business_capgo:
    '<strong class="text-white">Capgo:</strong> <strong class="text-emerald-400">Bootstrapped family business</strong>. No investors, no debt. Profitable since year one.',
  capwesome_diff_business_capgo_li1: 'Legal entities in both US and Europe',
