export function formatMessage(value: string, values: MessageValues = {}): string {
  return value.replace(/\{([A-Za-z0-9_]+)\}/g, (match, key: string) => {
    const replacement = values[key]
    return replacement === undefined || replacement === null ? match : String(replacement)
  })
}

export type MessageKey = keyof typeof messages
export type MessageFunction = (values?: MessageValues, _options?: unknown) => string
export type CopyMessages = Record<MessageKey, MessageFunction> & Record<string, MessageFunction>

const messageFunctions = new Map<string, MessageFunction>()

function getMessageFunction(key: string): MessageFunction {
  const cached = messageFunctions.get(key)
  if (cached) return cached

  if (!(key in messages)) {
    throw new Error(`Missing copy message: ${key}`)
  }

  const message = messages[key as MessageKey]
  const messageFunction: MessageFunction = (values = {}) => formatMessage(message, values)
  messageFunctions.set(key, messageFunction)
  return messageFunction
}

const copyMessages = new Proxy({} as CopyMessages, {
  get(_target, property) {
    if (typeof property !== 'string') return undefined
    if (property === 'then' || property === 'default' || property === '__esModule') return undefined
    return getMessageFunction(property)
  },
})

export default copyMessages
